    private fun String.toGranularityTimeframe(): StatsTimeframe? {
        return when (this.lowercase()) {
            "day" -> StatsTimeframe.DAY
            "week" -> StatsTimeframe.WEEK
            "month" -> StatsTimeframe.MONTH
            "year" -> StatsTimeframe.YEAR
            else -> null
        }
    }

    private fun List<String>.toStatsSegments(host: String?): List<String> {
        // `wordpress://stats/...`
        if (host == STATS_PATH) return this

        // `https://wordpress.com/stats/...`
        val statsIndex = indexOf(STATS_PATH)
        return if (statsIndex > -1) drop(statsIndex + 1) else emptyList()
    }

    private fun List<String>.toStatsTimeframe(): StatsTimeframe? {
        if (isEmpty()) return null

        // Prefer a granularity-based timeframe (day/week/month/year) when present.
        lastOrNull { it.toGranularityTimeframe() != null }?.let { return it.toGranularityTimeframe() }

        val tokens = map { it.lowercase() }

        if (tokens.contains("insights")) {
            return StatsTimeframe.INSIGHTS
        }

        if (tokens.contains("subscribers") || tokens.contains("followers")) {
            return if (statsTrafficSubscribersTabFeatureConfig.isEnabled()) {
                StatsTimeframe.SUBSCRIBERS
            } else {
                StatsTimeframe.INSIGHTS
            }
        }

        if (tokens.contains("traffic")) {
            return if (statsTrafficSubscribersTabFeatureConfig.isEnabled()) {
                StatsTimeframe.TRAFFIC
            } else {
                StatsTimeframe.INSIGHTS
            }
        }

        return null
    }"}

